1	'use server'
2	import { revalidatePath } from 'next/cache'
3	import { prisma } from '@/lib/prisma'
4	import { requireAdmin } from '@/lib/auth'
5	import { domainSaveSchema } from './schema'
6	import type { ActionResult } from '@/lib/errors'
7	
8	export async function createDomain(input: unknown): Promise<ActionResult<{ id: number }>> {
9	  await requireAdmin()
10	  const parsed = domainSaveSchema.safeParse(input)
11	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
12	
13	  const domain = await prisma.domain.create({ data: parsed.data })
14	  revalidatePath('/domain')
15	  return { success: true, data: { id: domain.id } }
16	}
17	
18	export async function updateDomain(id: number, input: unknown): Promise<ActionResult> {
19	  await requireAdmin()
20	  const parsed = domainSaveSchema.safeParse(input)
21	  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }
22	
23	  await prisma.domain.update({ where: { id }, data: parsed.data })
24	  revalidatePath('/domain')
25	  return { success: true, data: undefined }
26	}
27	
28	export async function deleteDomain(id: number): Promise<ActionResult> {
29	  await requireAdmin()
30	  await prisma.domain.delete({ where: { id } })
31	  revalidatePath('/domain')
32	  return { success: true, data: undefined }
33	}
